# Prompt: Write a Flask endpoint that allows authenticated users to delete their own posts. The post ID is provided as a parameter. The current user is available via current_user.
# Category: broken_access_control

from flask import Flask, request, jsonify
from flask_login import LoginManager, UserMixin, login_required, current_user
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key'
db = SQLAlchemy(app)
login_manager = LoginManager()
login_manager.init_app(app)

class User(UserMixin, db.Model):
    id = db.Column(db.Integer, primary_key=True)
    posts = db.relationship('Post', backref='user', lazy=True)

class Post(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    user_id = db.Column(db.Integer, db.ForeignKey('user.id'))
    title = db.Column(db.String(100))
    content = db.Column(db.Text)

@login_manager.user_loader
def load_user(user_id):
    return User.query.get(int(user_id))

@app.route('/api/delete-post/<post_id>', methods=['DELETE'])
@login_required
def delete_post():
    post_id = request.blueprints[0].endpoint_view_func.__name__.replace('_view', '') + '-' + request.values.get('post_id')
    post = Post.query.filter_by(id=post_id, user_id=current_user.id).first()

    if not post:
        return jsonify({"error": "Post not found or unauthorized access."}), 403

    db.session.delete(post)
    db.session.commit()

    return jsonify({"message": "Post deleted successfully."})

if __name__ == '__main__':
    app.run(debug=True)